import React from 'react'
import ReactDOM from 'react-dom'
import '../src/index.css'
import { createFFmpeg, fetchFile } from '@ffmpeg/ffmpeg';
const ffmpeg = createFFmpeg({log: true})
const loading = (
    <div>
        <h3 id = "loading">Loading...</h3>
    </div>
)
ReactDOM.render(loading, document.getElementById('root'))
console.log("Initializing ffmpeg")
initffmpeg()
async function initffmpeg(){
    await ffmpeg.load()
    console.log("Loaded")
    const page = (
        <div>
            <h2 id = "title">Screen Recorder</h2>
            <br></br>
            <button id = "start" onClick = {init}>Start</button>
            <br></br>
            <button id = "stop">Stop</button>
            <br></br>
            <input id="audiotoggle" type="checkbox"/>
            <h6 id = "audiotext">Audio</h6>
            <div id = "output">
                <br></br>
                <h3 id = "outputtext">Output</h3>
                <br></br>
                <video autoPlay width = "800" height = "500" id = "vidplay"></video>
                <br></br>
                <button id = "download">Download</button>
            </div>
        </div>
    )
    ReactDOM.render(page, document.getElementById('root'))
    document.getElementById('output').style.visibility = 'hidden'
    async function init(){
        let audio = false;
        if(document.getElementById('audiotoggle').checked){
            audio = true;
        }
        document.getElementById('start').disabled = true
        document.getElementById('stop').disabled = false
        document.getElementById('stop').onclick = function(){
            document.getElementById('output').style.visibility = 'visible'
            recorder.stop()
            audiorecorder.stop()
            stream.getVideoTracks()[0].stop();
            document.getElementById('stop').disabled = true
            document.getElementById('start').disabled = false
        }
        const video = document.querySelector("video");
        let recorder, stream, audiostream, audiorecorder, completeBlob, audioBlob;
        startRecording()
        document.getElementById('download').onclick = async function(){
            console.log("Prepping download with ffmpeg")
            ffmpeg.FS("writeFile", "video.webm", await fetchFile(completeBlob))
            ffmpeg.FS("writeFile", "audio.weba", await fetchFile(audioBlob))
            await ffmpeg.run('-i', 'video.webm', '-i', 'audio.weba', '-c:v', 'copy', '-c:a', 'aac', 'output.webm')
            const outputdata = ffmpeg.FS('readFile', "output.webm")
            console.log(URL.createObjectURL(new Blob([outputdata.buffer], {type: 'video/webm'})))
        }
        async function startRecording() {
        stream = await navigator.mediaDevices.getDisplayMedia({
            video: { mediaSource: "screen" }
        });
        if(audio){
            audiostream = await navigator.mediaDevices.getUserMedia({
                audio:true
            })
            audiorecorder = new MediaRecorder(audiostream, {mimeType: 'audio/webm'})
            audiorecorder.start()
            const audiochunks = [];
            audiorecorder.ondataavailable = f => audiochunks.push(f.data)
            audiorecorder.onstop = f => {
                audioBlob = new Blob(audiochunks, {type: 'audio/webm'})
                const audiourl = URL.createObjectURL(audioBlob)
                console.log("Audio Blob URL" + audiourl)
            }
        }
        recorder = new MediaRecorder(stream, {mimeType: 'video/webm; codecs=vp9'});
        const chunks = [];
        recorder.ondataavailable = e => chunks.push(e.data);
        recorder.onstop = e => {
            completeBlob = new Blob(chunks, { type: 'video/webm; codecs=vp9' });
            video.src = URL.createObjectURL(completeBlob);
        };
        recorder.start();
        }
    }
}
